INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("vo_travel_talk_20018_01", 20182, "", 1201820007, "vo_travel_talk", "", "", 21, "", 0, 0);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("陛下直々のご命令とあれば、\nこのクレジッタ・キャッシュ！\nご満足いただける大秘宝を、\nなんとしても手に入れてみせますわ！", 20182, 0, 1201820008, 118011, 0, 1, 11, 0, 1, 10);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", 20182, "", 1201820009, 0, "", "", 91, "", "", "");
