INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("vo_travel_talk_20018_02", 20182, "", 1201820011, "vo_travel_talk", "", "", 21, "", 0, 0);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("……それに、手ぶらで帰ったとなると\n秘書にまた小言を言われそうですし。\nあの子がグゥの音も出なくなるくらい\n稼いで稼いで稼ぎますわよ～っ！", 20182, 0, 1201820012, 118011, 0, 1, 11, 0, 1, 10);
INSERT INTO `v1_b2b69d7e076505cb5cba1466d0595b37c3960b57f1bfd1e4eaf2790fe54d48c8` VALUES ("", 20182, "", 1201820013, 0, "", "", 91, "", "", "");
